//! Substrate bridge for distributed inference
//!
//! Threads god formula + Buleyean probability into node selection,
//! load balancing, and inference result sealing.
//!
//! Lean: GodFormula.lean -- w(R,v) = R - min(v,R) + 1
//! Lean: ProvableRandomness.lean -- Lacey64 Weyl+mix sealing
//!
//! This module bridges the universal substrate (Fano routing, god formula,
//! Buleyean probability) into the distributed inference layer. It replaces
//! greedy latency sort with topology-aware node selection and adds anti-tamper
//! sealing on inference results.
//!
//! Integration points:
//!
//! 1. **Node selection** -- god formula weight ranks nodes by reliability
//!    (fewer rejections = higher weight), not just raw latency.
//!
//! 2. **Load distribution** -- Buleyean distribution normalizes god formula
//!    weights into a probability distribution across mesh nodes, ensuring
//!    all nodes receive some work (no starvation).
//!
//! 3. **Convergence tracking** -- inference Bule measures how balanced the
//!    mesh is: 0 = perfect equilibrium, higher = more skewed.
//!
//! 4. **Anti-tamper sealing** -- Lacey64 Weyl+mix hash of inference output
//!    bytes provides a deterministic, non-cryptographic seal for detecting
//!    result corruption in transit.

/// The Weyl/Kronecker conjugate multiplier (Golden Ratio inverse).
/// Identical to `gnosis_chaos::swarm::WEYL_MULTIPLIER`.
/// Provides an exact aperiodic uniform distribution.
const WEYL_MULTIPLIER: u64 = 0x9E3779B97F4A7C15;

/// God formula node selection weight.
///
/// `w(R, v) = R - min(v, R) + 1`
///
/// where `R` = round (resource budget / opportunity count) and
/// `v` = rejections (failures accumulated by this node).
///
/// Always >= 1. Nodes with fewer failures get more weight.
/// Mirrors `polyglot::substrate_bridge::admission_score`,
/// `gnosis_chaos::swarm::SwarmAgent::buleyean_weight`, and
/// `monster_swarm::budget::FleetProfile::stability_weight`.
#[inline(always)]
pub fn node_selection_weight(round: u32, rejections: u32) -> u32 {
    let capped = rejections.min(round);
    (round - capped).saturating_add(1)
}

/// Buleyean load distribution across mesh nodes.
///
/// Computes a probability distribution from per-node rejection counts
/// using the god formula as the weighting function. Each node's weight
/// is `w(round, rejections[i])`, then normalized so the distribution
/// sums to 1.0.
///
/// Guarantees:
///   - All probabilities > 0 (god formula is always >= 1)
///   - Sum of probabilities = 1.0 (within floating-point tolerance)
///   - Nodes with fewer rejections receive higher probability
///
/// Returns an empty vec if `node_rejections` is empty.
pub fn buleyean_load_distribution(node_rejections: &[u32], round: u32) -> Vec<f64> {
    if node_rejections.is_empty() {
        return Vec::new();
    }

    let weights: Vec<u64> = node_rejections
        .iter()
        .map(|&rej| node_selection_weight(round, rej) as u64)
        .collect();

    let total: u64 = weights.iter().sum();
    // total is always >= node_rejections.len() since each weight >= 1
    let total_f = total as f64;

    weights.iter().map(|&w| w as f64 / total_f).collect()
}

/// Inference Bule: convergence distance across the mesh.
///
/// Measures how far the mesh is from balanced load distribution.
/// Returns the difference between the maximum and minimum god formula
/// weights across all nodes. A return value of 0 means all nodes have
/// identical weight (perfect equilibrium).
///
/// Returns 0 for empty input (vacuous equilibrium).
pub fn inference_bule(node_rejections: &[u32]) -> u32 {
    if node_rejections.is_empty() {
        return 0;
    }

    let min_rej = node_rejections.iter().copied().min().unwrap_or(0);
    let max_rej = node_rejections.iter().copied().max().unwrap_or(0);

    // The Bule is the spread of rejections themselves.
    // Since god formula is monotone decreasing in rejections (for fixed round),
    // max_weight - min_weight = (R - min(min_rej, R) + 1) - (R - min(max_rej, R) + 1)
    //                         = min(max_rej, R) - min(min_rej, R)
    // But we express it directly as the rejection spread, which is equivalent
    // for the purpose of convergence tracking and avoids needing a round parameter.
    max_rej - min_rej
}

/// Lacey64 Weyl+mix seal of inference result bytes.
///
/// Deterministic, non-cryptographic hash for anti-tamper detection.
/// Uses the Weyl sequence (golden ratio multiplier) with a mix step
/// that folds each byte of the result into the running state.
///
/// The seal is NOT a cryptographic commitment -- it detects accidental
/// corruption and naive tampering, not adversarial forgery. For
/// cryptographic integrity, layer SHA-256 or ECDSA on top (see
/// `monster_swarm` signing).
pub fn seal_inference_result(result_bytes: &[u8]) -> u64 {
    let mut state: u64 = result_bytes.len() as u64;

    // Process 8 bytes at a time for throughput
    let chunks = result_bytes.chunks_exact(8);
    let remainder = chunks.remainder();

    for chunk in chunks {
        let word = u64::from_le_bytes([
            chunk[0], chunk[1], chunk[2], chunk[3], chunk[4], chunk[5], chunk[6], chunk[7],
        ]);
        // Weyl step: multiply by golden ratio inverse
        state = state.wrapping_add(word);
        state = state.wrapping_mul(WEYL_MULTIPLIER);
        // Mix: fold high bits back into low bits (avalanche)
        state ^= state >> 32;
    }

    // Handle remaining bytes
    if !remainder.is_empty() {
        let mut tail: u64 = 0;
        for (i, &byte) in remainder.iter().enumerate() {
            tail |= (byte as u64) << (i * 8);
        }
        state = state.wrapping_add(tail);
        state = state.wrapping_mul(WEYL_MULTIPLIER);
        state ^= state >> 32;
    }

    // Final mix to ensure full avalanche
    state = state.wrapping_mul(WEYL_MULTIPLIER);
    state ^= state >> 32;

    state
}

/// Verify that an inference result matches its seal.
///
/// Re-computes the Lacey64 seal and compares. Returns true iff the
/// result bytes have not been modified since sealing.
#[inline]
pub fn verify_inference_seal(result_bytes: &[u8], seal: u64) -> bool {
    seal_inference_result(result_bytes) == seal
}

/// Admit an inference node into the mesh.
///
/// Evaluates three gates from the universal admission certificate system:
///   1. God formula weight must exceed threshold (weight > 1, i.e. not fully rejected)
///   2. Seal must match expected seal (anti-tamper / Lacey64)
///   3. Rejection ratio must be < 0.9 (node is not chronically failing)
///
/// Returns `(admitted, weight, reason)`.
///
/// Lean provenance:
///   GodFormula.lean           -- w(R,v) = R - min(v,R) + 1
///   ProvableRandomness.lean   -- Lacey64 seal integrity
pub fn admit_inference_node(
    round: u32,
    rejections: u32,
    seal: u64,
    expected_seal: u64,
) -> (bool, u32, &'static str) {
    let weight = node_selection_weight(round, rejections);

    // Gate 1: anti-tamper -- seal must match
    if seal != expected_seal {
        return (
            false,
            weight,
            "Rejected: seal mismatch (anti-tamper gate failed)",
        );
    }

    // Gate 2: rejection ratio -- chronic failures rejected
    // For round > 0, ratio = rejections / round. Reject when >= 0.9.
    if round > 0 {
        // Use integer arithmetic: rejections * 10 >= round * 9
        let rej_scaled = (rejections as u64) * 10;
        let round_scaled = (round as u64) * 9;
        if rej_scaled >= round_scaled {
            return (
                false,
                weight,
                "Rejected: rejection ratio >= 0.9 (behavioral gate failed)",
            );
        }
    }

    // Gate 3: god formula positivity (always holds by construction, but
    // verifying explicitly for certificate integrity)
    if weight == 0 {
        return (
            false,
            weight,
            "Rejected: god formula weight is zero (should be unreachable)",
        );
    }

    (true, weight, "Inference node admitted")
}

#[cfg(test)]
mod tests {
    use super::*;

    // ---------------------------------------------------------------
    // Node weight always positive (god formula guarantee)
    // ---------------------------------------------------------------

    #[test]
    fn node_weight_always_positive() {
        // Edge cases
        assert_eq!(node_selection_weight(0, 0), 1);
        assert_eq!(node_selection_weight(0, 100), 1);
        assert_eq!(node_selection_weight(100, 0), 101);
        assert_eq!(node_selection_weight(100, 100), 1);
        assert_eq!(node_selection_weight(100, 50), 51);
        assert_eq!(node_selection_weight(u32::MAX, u32::MAX), 1);
        assert_eq!(node_selection_weight(u32::MAX, 0), u32::MAX); // saturates

        // Brute-force sweep
        for round in 0..256u32 {
            for rej in 0..256u32 {
                let w = node_selection_weight(round, rej);
                assert!(
                    w >= 1,
                    "node_selection_weight({round}, {rej}) = {w}, must be >= 1"
                );
            }
        }
    }

    #[test]
    fn node_weight_matches_polyglot_admission_score() {
        // Cross-validate against the polyglot substrate bridge's formula
        fn reference_god_weight(budget: u32, rejection: u32) -> u32 {
            budget.saturating_sub(rejection.min(budget)) + 1
        }
        for b in 0..512u32 {
            for r in 0..512u32 {
                assert_eq!(
                    node_selection_weight(b, r),
                    reference_god_weight(b, r),
                    "mismatch at round={b}, rejections={r}"
                );
            }
        }
    }

    // ---------------------------------------------------------------
    // Distribution sums to ~1.0
    // ---------------------------------------------------------------

    #[test]
    fn distribution_sums_to_one() {
        let cases: Vec<(Vec<u32>, u32)> = vec![
            (vec![0], 10),
            (vec![0, 0, 0], 10),
            (vec![0, 5, 10], 10),
            (vec![1, 2, 3, 4, 5], 20),
            (vec![100, 100, 100], 100),
            (vec![0, 0, 0, 0, 0, 0, 0], 7), // 7 nodes (Fano)
        ];
        for (rejections, round) in cases {
            let dist = buleyean_load_distribution(&rejections, round);
            assert_eq!(dist.len(), rejections.len());
            let sum: f64 = dist.iter().sum();
            assert!(
                (sum - 1.0).abs() < 1e-10,
                "distribution sum = {sum}, expected ~1.0 for rejections={rejections:?}, round={round}"
            );
            // All probabilities > 0
            for (i, &p) in dist.iter().enumerate() {
                assert!(p > 0.0, "p[{i}] = {p}, must be > 0");
            }
        }
    }

    #[test]
    fn distribution_empty_input() {
        let dist = buleyean_load_distribution(&[], 10);
        assert!(dist.is_empty());
    }

    #[test]
    fn distribution_favors_fewer_rejections() {
        // Node 0 has 0 rejections, node 1 has 5
        let dist = buleyean_load_distribution(&[0, 5], 10);
        assert!(
            dist[0] > dist[1],
            "node with 0 rejections (p={}) should get more weight than node with 5 (p={})",
            dist[0],
            dist[1]
        );
    }

    // ---------------------------------------------------------------
    // Balanced nodes -> Bule 0
    // ---------------------------------------------------------------

    #[test]
    fn balanced_nodes_bule_zero() {
        assert_eq!(inference_bule(&[0, 0, 0]), 0);
        assert_eq!(inference_bule(&[5, 5, 5, 5]), 0);
        assert_eq!(inference_bule(&[100, 100]), 0);
        assert_eq!(inference_bule(&[]), 0);
    }

    #[test]
    fn unbalanced_nodes_nonzero_bule() {
        assert_eq!(inference_bule(&[0, 10]), 10);
        assert_eq!(inference_bule(&[5, 15, 10]), 10);
        assert_eq!(inference_bule(&[0, 100]), 100);
    }

    #[test]
    fn single_node_bule_zero() {
        assert_eq!(inference_bule(&[42]), 0);
    }

    // ---------------------------------------------------------------
    // Seal is deterministic
    // ---------------------------------------------------------------

    #[test]
    fn seal_deterministic() {
        let data = b"The quick brown fox jumps over the lazy dog";
        let seal1 = seal_inference_result(data);
        let seal2 = seal_inference_result(data);
        assert_eq!(seal1, seal2, "seal must be deterministic");

        // Different data -> different seal
        let other = b"The quick brown fox jumps over the lazy cat";
        let seal3 = seal_inference_result(other);
        assert_ne!(seal1, seal3, "different data should produce different seal");
    }

    #[test]
    fn seal_empty_input() {
        // Empty input should produce a valid seal (not panic)
        let seal = seal_inference_result(b"");
        // Re-seal should match
        assert_eq!(seal, seal_inference_result(b""));
    }

    #[test]
    fn seal_various_lengths() {
        // Test across chunk boundaries (8-byte aligned and not)
        for len in [1, 7, 8, 9, 15, 16, 17, 31, 32, 33, 63, 64, 100, 1024] {
            let data: Vec<u8> = (0..len).map(|i| (i % 256) as u8).collect();
            let seal = seal_inference_result(&data);
            assert_eq!(
                seal,
                seal_inference_result(&data),
                "non-deterministic at len={len}"
            );
        }
    }

    // ---------------------------------------------------------------
    // Tampered result fails verification
    // ---------------------------------------------------------------

    #[test]
    fn tampered_result_fails_verification() {
        let data = b"inference output tensor bytes 0123456789abcdef";
        let seal = seal_inference_result(data);

        // Original verifies
        assert!(verify_inference_seal(data, seal));

        // Single-byte tamper at every position
        for i in 0..data.len() {
            let mut tampered = data.to_vec();
            tampered[i] ^= 0x01; // flip one bit
            assert!(
                !verify_inference_seal(&tampered, seal),
                "tampered byte at position {i} should fail verification"
            );
        }

        // Wrong seal fails
        assert!(!verify_inference_seal(data, seal.wrapping_add(1)));
        assert!(!verify_inference_seal(data, 0));

        // Truncated data fails
        assert!(!verify_inference_seal(&data[..data.len() - 1], seal));
    }

    #[test]
    fn verify_empty_sealed_correctly() {
        let seal = seal_inference_result(b"");
        assert!(verify_inference_seal(b"", seal));
        assert!(!verify_inference_seal(b"x", seal));
    }

    // ---------------------------------------------------------------
    // Integration: weight -> distribution -> bule compose
    // ---------------------------------------------------------------

    // ---------------------------------------------------------------
    // Admission: admit_inference_node
    // ---------------------------------------------------------------

    #[test]
    fn admit_inference_node_healthy() {
        let seal = 0xDEAD_BEEF_CAFE_1234u64;
        let (admitted, weight, reason) = admit_inference_node(10, 2, seal, seal);
        assert!(admitted, "healthy node should be admitted");
        assert_eq!(weight, 9); // 10 - min(2,10) + 1 = 9
        assert!(reason.contains("admitted"), "reason: {reason}");
    }

    #[test]
    fn admit_inference_node_seal_mismatch() {
        let (admitted, _weight, reason) = admit_inference_node(10, 0, 0xAAAA, 0xBBBB);
        assert!(!admitted, "seal mismatch should reject");
        assert!(
            reason.contains("seal"),
            "reason should mention seal: {reason}"
        );
    }

    #[test]
    fn admit_inference_node_high_rejection_ratio() {
        // rejections = 9, round = 10 -> ratio = 0.9 -> rejected
        let seal = 42u64;
        let (admitted, weight, reason) = admit_inference_node(10, 9, seal, seal);
        assert!(!admitted, "high rejection ratio should reject");
        assert_eq!(weight, 2); // 10 - 9 + 1
        assert!(reason.contains("rejection"), "reason: {reason}");
    }

    #[test]
    fn admit_inference_node_round_zero() {
        let seal = 1u64;
        let (admitted, weight, reason) = admit_inference_node(0, 0, seal, seal);
        assert!(admitted, "round 0 with 0 rejections should admit");
        assert_eq!(weight, 1);
        assert!(reason.contains("admitted"), "reason: {reason}");
    }

    #[test]
    fn admit_inference_node_boundary_rejection_ratio() {
        // rejections = 8, round = 10 -> ratio = 0.8 -> admitted (< 0.9)
        let seal = 7u64;
        let (admitted, weight, reason) = admit_inference_node(10, 8, seal, seal);
        assert!(admitted, "0.8 rejection ratio should still admit");
        assert_eq!(weight, 3); // 10 - 8 + 1
        assert!(reason.contains("admitted"), "reason: {reason}");
    }

    #[test]
    fn substrate_integration_weight_distribution_bule() {
        let rejections = vec![0u32, 3, 7, 1, 5];
        let round = 10;

        // Weights should all be positive
        for &rej in &rejections {
            assert!(node_selection_weight(round, rej) >= 1);
        }

        // Distribution should sum to 1
        let dist = buleyean_load_distribution(&rejections, round);
        let sum: f64 = dist.iter().sum();
        assert!((sum - 1.0).abs() < 1e-10);

        // Bule should be max_rej - min_rej = 7 - 0 = 7
        assert_eq!(inference_bule(&rejections), 7);

        // Node 0 (0 rejections) should have highest probability
        let max_p = dist.iter().cloned().fold(f64::NEG_INFINITY, f64::max);
        assert_eq!(dist[0], max_p);
    }
}
